window.genImgPath = function(field, cat, qid){
  var f = (qid && window.QUESTION_IMG[qid]) || (window.CAT_IMG[field+'|'+cat]) || (window.FIELD_DEF_IMG[field]) || null;
  return f ? ('content/images/'+f) : null;
};
// Returns an <img> wrapper HTML for a question, or "" if no mapping. Missing files self-remove.
window.genImgHTML = function(field, cat, qid, cls){
  var p = window.genImgPath(field, cat, qid);
  if(!p) return "";
  return '<div class="gen-fig-wrap '+(cls||'')+'"><img class="gen-fig" src="'+p+'" alt="" onerror="var w=this.closest(\'.gen-fig-wrap\'); if(w) w.remove();"></div>';
};
